前導期偏誤的問題？', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:39+00:00", "source_pdf_sha1": "d824b48a77b5", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "342", "s": "2807", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "流行病學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "衛生行政"}'::jsonb, NULL)
